/*
 * INPUT GUARD — validation + normalization + idempotency key
 * ─────────────────────────────────────────────────────────
 * Fails fast on bad input (invalid email, missing fields).
 * Stamps every item with a stable traceId for log correlation.
 */

const body = $input.first().json.body ?? $input.first().json;

// ── Validation ────────────────────────────────────────────────────
const REQUIRED = ['email', 'firstName', 'lastName'];
const missing  = REQUIRED.filter(f => !body[f]?.toString().trim());
if (missing.length) {
  throw new Error(`VALIDATION_ERROR: missing required fields [${missing.join(', ')}]`);
}

// ── Email format check ────────────────────────────────────────────
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const email    = body.email.toLowerCase().trim();
if (!EMAIL_RE.test(email)) {
  throw new Error(`VALIDATION_ERROR: invalid email format [${email}]`);
}

// ── Block free / disposable domains ──────────────────────────────
const BLOCKED_DOMAINS = ['mailinator.com','guerrillamail.com','throwaway.email','temp-mail.org'];
const domain = email.split('@')[1];
if (BLOCKED_DOMAINS.includes(domain)) {
  throw new Error(`VALIDATION_ERROR: disposable email domain [${domain}]`);
}

// ── Idempotency key (stable per email + source) ───────────────────
const crypto = require('crypto');
const idempotencyKey = crypto
  .createHash('sha256')
  .update(`${email}:${body.source ?? 'unknown'}`)
  .digest('hex')
  .slice(0, 16);

const traceId = `tr-lead-${idempotencyKey}`;
const leadId  = `LEAD-${idempotencyKey.toUpperCase()}`;

// ── Canonical lead schema ─────────────────────────────────────────
return [{
  json: {
    // Identity
    traceId,
    leadId,
    idempotencyKey,

    // Contact
    firstName:   body.firstName.trim(),
    lastName:    body.lastName.trim(),
    email,
    domain,
    phone:       body.phone?.trim()   || null,
    company:     body.company?.trim() || null,
    jobTitle:    body.jobTitle?.trim() || null,

    // Attribution
    source:      body.source     || 'webhook',
    utmSource:   body.utmSource  || null,
    utmMedium:   body.utmMedium  || null,
    utmCampaign: body.utmCampaign || null,
    pageUrl:     body.pageUrl    || null,

    // Pipeline metadata
    ingestedAt:  new Date().toISOString(),
    enrichment:  { clearbit: null, hunter: null },
    score:       { total: 0, breakdown: {} },
    tier:        null
  }
}];

/*
 * ENRICHMENT MERGE + SCORING ENGINE
 * ──────────────────────────────────────────────────────────────────
 * Defensive merge: treats every enrichment source as optional.
 * Scoring is table-driven — easy to extend without touching logic.
 */

const items   = $input.all();
const lead    = items[0].json;                             // original lead
const cbRaw   = items[1]?.json;                            // Clearbit response
const hnRaw   = items[2]?.json;                            // Hunter response

// ── Safe extraction helpers ───────────────────────────────────────
const cb = (cbRaw?.statusCode >= 200 && cbRaw?.statusCode < 300)
  ? (cbRaw.body ?? {}) : {};
const hn = (hnRaw?.statusCode >= 200 && hnRaw?.statusCode < 300)
  ? (hnRaw.body?.data ?? {}) : {};

// ── Scoring table ────────────────────────────────────────────────
// { signal, points, test(lead, cb, hn) → boolean, label }
const SCORING_TABLE = [
  { signal: 'email_verified',   points: 20, label: 'Email verified',      test: (_l,_c,h) => h.status === 'valid' },
  { signal: 'company_found',    points: 25, label: 'Company data found',   test: (_l,c)   => !!c.name },
  { signal: 'enterprise',       points: 30, label: 'Enterprise (1000+)',   test: (_l,c)   => (c.metrics?.employees ?? 0) >= 1000 },
  { signal: 'midmarket',        points: 20, label: 'Mid-market (100-999)', test: (_l,c)   => { const e = c.metrics?.employees ?? 0; return e >= 100 && e < 1000; } },
  { signal: 'smb',              points: 10, label: 'SMB (10-99)',          test: (_l,c)   => { const e = c.metrics?.employees ?? 0; return e >= 10 && e < 100; } },
  { signal: 'has_phone',        points: 10, label: 'Phone provided',       test: (l)      => !!l.phone },
  { signal: 'has_job_title',    points:  5, label: 'Job title provided',   test: (l)      => !!l.jobTitle },
  { signal: 'tech_stack',       points: 15, label: 'Tech stack detected',  test: (_l,c)   => (c.tech?.length ?? 0) > 0 },
  { signal: 'has_website',      points:  5, label: 'Website available',    test: (_l,c)   => !!c.domain },
  { signal: 'paid_source',      points: 10, label: 'Paid acquisition',     test: (l)      => l.utmMedium === 'cpc' || l.utmMedium === 'paid' },
];

const breakdown = {};
let total = 0;
for (const rule of SCORING_TABLE) {
  const hit = rule.test(lead, cb, hn);
  breakdown[rule.signal] = { points: hit ? rule.points : 0, label: rule.label, matched: hit };
  if (hit) total += rule.points;
}
total = Math.min(total, 100); // cap at 100

const tier = total >= 65 ? 'HOT' : total >= 40 ? 'WARM' : 'COLD';

// ── Merged enrichment ────────────────────────────────────────────
const enriched = {
  ...lead,

  // Override / fill from enrichment
  company:          lead.company  || cb.name    || null,
  companyDomain:    cb.domain     || lead.domain,
  companySize:      cb.metrics?.employees       || null,
  companyIndustry:  cb.category?.industry       || null,
  companySubIndustry: cb.category?.subIndustry  || null,
  companyCountry:   cb.geo?.country             || null,
  companyCity:      cb.geo?.city                || null,
  companyFounded:   cb.foundedYear              || null,
  companyType:      cb.type                     || null,
  techStack:        (cb.tech ?? []).slice(0, 8),
  alexaRank:        cb.metrics?.alexaGlobalRank || null,

  emailStatus:      hn.status     || 'unknown',
  emailScore:       hn.score      || null,

  enrichment: {
    clearbitSuccess: !!cb.name,
    hunterSuccess:   !!hn.status,
    enrichedAt:      new Date().toISOString()
  },

  score: { total, breakdown },
  tier,
};

return [{ json: enriched }];

// Build rich Slack Block Kit notification for HOT leads
const l = $input.first().json;
const topSignals = Object.entries(l.score.breakdown)
  .filter(([, v]) => v.matched)
  .map(([, v]) => `• ${v.label} (+${v.points})`)
  .join('\n');

return [{
  json: {
    ...l,
    slackBlocks: [
      {
        type: 'header',
        text: { type: 'plain_text', text: '🔥 HOT LEAD — Immediate Action Required', emoji: true }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*Name:*\n${l.firstName} ${l.lastName}` },
          { type: 'mrkdwn', text: `*Email:*\n${l.email}` },
          { type: 'mrkdwn', text: `*Company:*\n${l.company ?? 'Unknown'}` },
          { type: 'mrkdwn', text: `*Industry:*\n${l.companyIndustry ?? 'N/A'}` },
          { type: 'mrkdwn', text: `*Company Size:*\n${l.companySize ? l.companySize + ' employees' : 'Unknown'}` },
          { type: 'mrkdwn', text: `*Score:*\n${l.score.total}/100 — ${l.tier}` }
        ]
      },
      {
        type: 'section',
        text: { type: 'mrkdwn', text: `*Scoring Signals Matched:*\n${topSignals || 'None'}` }
      },
      {
        type: 'context',
        elements: [
          { type: 'mrkdwn', text: `Lead ID: \`${l.leadId}\` | Trace: \`${l.traceId}\` | Source: ${l.source}` }
        ]
      },
      { type: 'divider' }
    ]
  }
}];

// Build concise Slack Block Kit notification for WARM leads
const l = $input.first().json;
return [{
  json: {
    ...l,
    slackBlocks: [
      {
        type: 'section',
        text: { type: 'mrkdwn', text: `📊 *WARM Lead* — Follow up within 48h\n*${l.firstName} ${l.lastName}* | ${l.email} | ${l.company ?? 'Unknown company'}\nScore: ${l.score.total}/100 | LeadID: \`${l.leadId}\`` }
      }
    ]
  }
}];
